exercises.solution_code:
#include <iostream>
#include <string>
#include <string_view>

class Vehicle
{
private:
    std::string m_model{};

public:
    Vehicle(std::string_view model)
        : m_model{ model }
    {
    }

    std::string_view getModel() const { return m_model; }
};

class Truck : public Vehicle
{
private:
    int m_capacity{};
    int m_loaded{ 0 };

public:
    Truck(std::string_view model, int capacity)
        : Vehicle{ model }, m_capacity{ capacity }
    {
    }

    int getCapacity() const { return m_capacity; }

    void load(int amount)
    {
        m_loaded += amount;
        if (m_loaded > m_capacity)
            m_loaded = m_capacity;
    }

    int getLoaded() const { return m_loaded; }
};

int main()
{
    std::string model{};
    int capacity{};
    int amount{};
    std::cin >> model >> capacity >> amount;

    Truck truck{ model, capacity };
    truck.load(amount);

    std::cout << "Model: " << truck.getModel() << '\n';
    std::cout << "Capacity: " << truck.getCapacity() << '\n';
    std::cout << "Loaded: " << truck.getLoaded() << '\n';

    return 0;
}

