#include <iostream>
#include <string>
#include <string_view>

class BankAccount
{
private:
    std::string m_owner{};
    int m_balance{};

public:
    BankAccount(std::string_view owner, int balance)
        : m_owner{ owner }, m_balance{ balance }
    {
    }

    std::string_view getOwner() const { return m_owner; }
    int getBalance() const { return m_balance; }
    void deposit(int amount) { m_balance += amount; }
};

class SavingsAccount : public BankAccount
{
private:
    int m_rate{};

public:
    SavingsAccount(std::string_view owner, int balance, int rate)
        : BankAccount{ owner, balance }, m_rate{ rate }
    {
    }

    void applyInterest()
    {
        int interest{ getBalance() * m_rate / 100 };
        deposit(interest);
    }

    int getRate() const { return m_rate; }
};

int main()
{
    std::string owner{};
    int balance{};
    int rate{};
    int n{};
    std::cin >> owner >> balance >> rate >> n;

    SavingsAccount account{ owner, balance, rate };
    for (int i{ 0 }; i < n; ++i)
        account.applyInterest();

    std::cout << "Owner: " << account.getOwner() << '\n';
    std::cout << "Balance: " << account.getBalance() << '\n';

    return 0;
}
